import numpy as np

class MLP:
    """Multi-Layer Perceptron (réseau fully-connected)"""

    def __init__(self, layer_sizes):
        self.weights = []
        self.biases = []
        for i in range(len(layer_sizes) - 1):
            # Initialisation He (pour ReLU)
            W = np.random.randn(layer_sizes[i], layer_sizes[i+1]) * np.sqrt(2/layer_sizes[i])
            b = np.zeros(layer_sizes[i+1])
            self.weights.append(W)
            self.biases.append(b)

    def relu(self, x):
        return np.maximum(0, x)

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def forward(self, x):
        self.activations = [x]
        current = x
        for i, (W, b) in enumerate(zip(self.weights, self.biases)):
            z = current @ W + b
            # ReLU pour les couches cachées, sigmoid en sortie
            if i < len(self.weights) - 1:
                current = self.relu(z)
            else:
                current = self.sigmoid(z)
            self.activations.append(current)
        return current

# Architecture : 2 entrées -> 4 neurones -> 3 neurones -> 1 sortie
mlp = MLP([2, 4, 3, 1])
x = np.array([[0.5, -0.3]])
output = mlp.forward(x)
print(f'Prédiction : {output[0,0]:.4f}')
print(f'Paramètres totaux : {sum(W.size + b.size for W,b in zip(mlp.weights, mlp.biases))}')

from mcp.server import Server
from mcp.server.stdio import stdio_server
from mcp.types import Tool, TextContent
import asyncio
import json

# Créer un serveur MCP personnalisé
app = Server('mon-serveur-metier')

# ── Déclarer les outils disponibles ──────────────
@app.list_tools()
async def list_tools() -> list[Tool]:
    return [
        Tool(
            name='get_product_info',
            description='Récupère les infos d\'un produit par son SKU',
            inputSchema={
                'type': 'object',
                'properties': {
                    'sku': {'type': 'string', 'description': 'SKU du produit'}
                },
                'required': ['sku']
            }
        ),
        Tool(
            name='check_stock',
            description='Vérifie le stock disponible d\'un produit',
            inputSchema={
                'type': 'object',
                'properties': {
                    'sku': {'type': 'string'},
                    'warehouse': {'type': 'string', 'default': 'PARIS'}
                },
                'required': ['sku']
            }
        )
    ]

# ── Implémenter l'exécution des outils ───────────
@app.call_tool()
async def call_tool(name: str, arguments: dict):
    if name == 'get_product_info':
        sku = arguments['sku']
        # En réalité : appel base de données
        product = {'sku': sku, 'name': 'Produit Demo', 'price': 29.99}
        return [TextContent(type='text', text=json.dumps(product))]

    elif name == 'check_stock':
        sku = arguments['sku']
        warehouse = arguments.get('warehouse', 'PARIS')
        stock = {'sku': sku, 'warehouse': warehouse, 'quantity': 42}
        return [TextContent(type='text', text=json.dumps(stock))]

# ── Lancer le serveur ─────────────────────────────
async def main():
    async with stdio_server() as (read_stream, write_stream):
        await app.run(read_stream, write_stream, app.create_initialization_options())

if __name__ == '__main__':
    asyncio.run(main())

